class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, i):
        if self.parent[i] == i:
            return i
        self.parent[i] = self.find(self.parent[i])
        return self.parent[i]

    def union(self, i, j):
        root_i = self.find(i)
        root_j = self.find(j)

        if root_i != root_j:
            if self.rank[root_i] < self.rank[root_j]:
                self.parent[root_i] = root_j
            elif self.rank[root_i] > self.rank[root_j]:
                self.parent[root_j] = root_i
            else:
                self.parent[root_j] = root_i
                self.rank[root_i] += 1
            return True
        return False

def solve_equations(equations, num_variables):
    uf = UnionFind(num_variables)

    for var1, var2, op in equations:
        if op == "==":
            uf.union(var1, var2)

    for var1, var2, op in equations:
        if op == "!=":
            if uf.find(var1) == uf.find(var2):
                return False

    return True
